mapper.select:
SELECT id, session_id, user_id, total_score, level, technical_score, expression_score,
       logic_score, completeness_score, innovation_score, suggestion, created_at
FROM interview_report WHERE id = #{id}

SELECT id, session_id, user_id, total_score, level, technical_score, expression_score,
       logic_score, completeness_score, innovation_score, suggestion, created_at
FROM interview_report WHERE session_id = #{sessionId}

SELECT r.id, r.session_id, r.user_id, r.total_score, r.level, r.technical_score,
       r.expression_score, r.logic_score, r.completeness_score, r.innovation_score,
       r.suggestion, r.created_at,
       s.position, s.round, s.difficulty
FROM interview_report r
INNER JOIN interview_session s ON r.session_id = s.id
WHERE r.user_id = #{userId}

  AND s.position = #{position}


  AND s.round = #{round}


  AND s.difficulty = #{difficulty}


  AND r.total_score >= #{scoreMin}


  AND r.total_score <= #{scoreMax}


  AND r.created_at >= #{startDate}


  AND r.created_at < DATE_ADD(#{endDate}, INTERVAL 1 DAY)

ORDER BY r.created_at DESC
LIMIT #{offset}, #{size}

SELECT COUNT(*)
FROM interview_report r
INNER JOIN interview_session s ON r.session_id = s.id
WHERE r.user_id = #{userId}

  AND s.position = #{position}


  AND s.round = #{round}


  AND s.difficulty = #{difficulty}


  AND r.total_score >= #{scoreMin}


  AND r.total_score <= #{scoreMax}


  AND r.created_at >= #{startDate}


  AND r.created_at < DATE_ADD(#{endDate}, INTERVAL 1 DAY)

SELECT r.id, r.session_id, r.user_id, r.total_score, r.level, r.technical_score,
       r.expression_score, r.logic_score, r.completeness_score, r.innovation_score,
       r.suggestion, r.created_at,
       s.position, s.round, s.difficulty
FROM interview_report r
INNER JOIN interview_session s ON r.session_id = s.id
WHERE r.user_id = #{userId}
  AND s.position = #{position}
ORDER BY r.created_at DESC
LIMIT #{offset}, #{size}

SELECT COUNT(*)
FROM interview_report r
INNER JOIN interview_session s ON r.session_id = s.id
WHERE r.user_id = #{userId}
  AND s.position = #{position}
